mapper.select:
SELECT c.id, c.title, c.summary, c.category_id AS categoryId, cat.name AS categoryName, c.author_id AS authorId, u.username AS authorName, c.status, c.content_type AS contentType, c.cover_image_id AS coverImageId, f.url AS coverImageUrl, c.view_count AS viewCount, c.sort, c.is_top AS isTop, c.is_hot AS isHot, c.publish_time AS publishTime, c.seo_title AS seoTitle, c.seo_keywords AS seoKeywords, c.seo_description AS seoDescription, c.create_time AS createTime, c.update_time AS updateTime FROM cms_content c LEFT JOIN cms_category cat ON c.category_id = cat.id LEFT JOIN sys_user u ON c.author_id = u.id LEFT JOIN sys_file f ON c.cover_image_id = f.id
c.del_flag = 'F'
AND c.title LIKE CONCAT('%', #{dto.title}, '%')
AND c.category_id = #{dto.categoryId}
AND c.author_id = #{dto.authorId}
AND c.status = #{dto.status}
AND c.content_type = #{dto.contentType}
AND c.is_top = #{dto.isTop}
AND c.is_hot = #{dto.isHot}
AND c.publish_time >= #{dto.publishTimeStart}
AND c.publish_time <= #{dto.publishTimeEnd}
ORDER BY c.is_top DESC, c.sort ASC, c.id DESC

mapper.update:
UPDATE cms_content 
SET view_count = IFNULL(view_count, 0) + 1 
WHERE id = #{id}
